/* Features grid */
.features-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:22px}
.feature-card{background:linear-gradient(180deg, rgba(255,255,255,0.02), rgba(255,255,255,0.01));border-radius:14px;padding:22px;box-shadow:var(--card-shadow);border:1px solid var(--glass-border);transition:transform .7s cubic-bezier(.16,.84,.44,1),opacity .6s ease;transform:translateY(0);opacity:1}
.feature-card h3{margin:14px 0 8px}
.feature-card p{color:var(--muted);margin:0}
.feature-icon{width:56px;height:56px;border-radius:12px;display:flex;align-items:center;justify-content:center;font-weight:800;background:linear-gradient(135deg,var(--accent-1),var(--accent-2));color:#041122;box-shadow:0 8px 20px rgba(7,12,30,0.5)}

/* Hidden animation state */
.hidden{opacity:0;transform:translateY(28px)}
.show{opacity:1;transform:translateY(0)}

/* Mission */
.mission-grid{display:grid;grid-template-columns:1fr 420px;gap:28px;align-items:center}
.mission-text h2{margin-top:0}
.glass-card{background:linear-gradient(135deg, rgba(255,255,255,0.02), rgba(255,255,255,0.01));padding:26px;border-radius:12px;border:1px solid var(--glass-border);box-shadow:0 12px 30px rgba(2,6,23,0.5)}

/* Footer */
.footer{padding:36px 0;border-top:1px solid rgba(255,255,255,0.02);color:var(--muted)}
.footer-grid{display:flex;justify-content:space-between;align-items:center}
.footer-links{display:flex;gap:14px}
.footer-links a{color:var(--muted);text-decoration:none}

/* Responsiveness */
@media (max-width:920px){
  .features-grid{grid-template-columns:1fr;}
  .mission-grid{grid-template-columns:1fr}
  .nav-inner{padding:10px}
  .hero-content{padding:40px 0}
}

@media (prefers-reduced-motion:reduce){
  .feature-card,.btn{transition:none}
}
